parameters.jsCode:
// WF-04 Plan: Kandidat finden + freien Tag berechnen (v1.1, robust gegen DE/EN-Naming)
//
// Eingabe: alle Items der Liste (aus SharePoint getAll)
// Ausgabe: 1 Item mit Feld 'decision' in {OK, NO_CANDIDATE, NO_FREE_DAY},
//          plus debug_first_item für Diagnose.

// === Konfiguration ===
const POOL_TYPES = [
  'Standard','Tipp','FAQ','Praxis-News','Aktion',
  'Mitarbeiter:in','Behind-the-Scenes','Team','Promo','Zitat'
];
const BLOCKING_TYPES = ['Reel','Story','Übung'];
const ACTIVE_STATUSES = ['Bereit','Freigegeben','Geplant','Veröffentlicht'];
const PREFERENCE_WEEKDAY = 2;
const ALTERNATE_WEEKDAY  = 4;
const MIN_LEAD_DAYS      = 3;
const POSTING_TIME       = '09:00';

// === Robuste Property-Lookups (DE+EN, Anzeigename+intern) ===
const pickField = (item, keys) => {
  const sources = [item && item.fields, item && item.Felder, item];
  for (const src of sources) {
    if (!src || typeof src !== 'object') continue;
    for (const k of keys) {
      if (k in src && src[k] !== undefined) return src[k];
    }
  }
  return null;
};
const getTyp    = (it) => pickField(it, ['field_2','Field_2','Post_Typ','PostTyp']);
const getStatus = (it) => pickField(it, ['field_6','Field_6','Status']);
const getDatum  = (it) => pickField(it, ['Ver_x00f6_ffentlichungsdatum','Veröffentlichungsdatum','Veroeffentlichungsdatum','field_4','Field_4']);
const getId     = (it) => it?.id ?? pickField(it, ['Ausweis','ID','AUSWEIS']) ?? null;
const getThema  = (it) => pickField(it, ['field_1','Field_1','Thema','Title','Titel']) ?? '(ohne Thema)';
const getLog    = (it) => pickField(it, ['field_13','Field_13','Log','Kommentare']) ?? '';
const getCreated= (it) => it?.createdDateTime ?? pickField(it, ['Created','Erstellt']);

const isEmptyDatum = (v) => v === null || v === undefined || v === '' || v === '0';

// === Einlesen ===
const items = $input.all().map(i => i.json);

// Debug: erstes Item komplett ausgeben (als String, da n8n sonst trunciert)
const debug_first_item = items[0] ? JSON.stringify(items[0]).substring(0, 2000) : 'NO_ITEMS';

// === Aktuellen Monat bestimmen ===
const now = new Date();
const year = now.getFullYear();
const month = now.getMonth();
const monthStart = new Date(Date.UTC(year, month, 1));
const nextMonthStart = new Date(Date.UTC(year, month + 1, 1));

// === Schritt 1: Kandidat finden ===
const poolCandidates = items.filter(it => {
  const typ = getTyp(it);
  const status = getStatus(it);
  const datum = getDatum(it);
  return POOL_TYPES.includes(typ) && status === 'Entwurf' && isEmptyDatum(datum);
}).sort((a,b) => {
  const ca = new Date(getCreated(a) || 0).getTime();
  const cb = new Date(getCreated(b) || 0).getTime();
  return ca - cb;
});

// Debug: was haben die Items so für Werte?
const debug_items_summary = items.slice(0, 5).map(it => ({
  id: getId(it),
  thema: getThema(it),
  typ: getTyp(it),
  status: getStatus(it),
  datum: getDatum(it),
  isEmpty: isEmptyDatum(getDatum(it))
}));

if (poolCandidates.length === 0) {
  return [{
    json: {
      decision: 'NO_CANDIDATE',
      year, month: month + 1,
      reason: 'Kein Entwurf-Item mit Pool-Post-Typ und leerem Veröffentlichungsdatum gefunden.',
      debug_total_items: items.length,
      debug_items_summary,
      debug_first_item
    }
  }];
}

const candidate = poolCandidates[0];
const candidate_id = getId(candidate);
const candidate_thema = getThema(candidate);
const candidate_typ = getTyp(candidate);
const candidate_log = getLog(candidate);

// === Schritt 2: Belegte Tage ===
const busyDays = new Set();
for (const it of items) {
  const datumRaw = getDatum(it);
  if (isEmptyDatum(datumRaw)) continue;
  const d = new Date(datumRaw);
  if (isNaN(d.getTime())) continue;
  if (d < monthStart || d >= nextMonthStart) continue;
  const status = getStatus(it);
  const typ = getTyp(it);
  if (ACTIVE_STATUSES.includes(status) || BLOCKING_TYPES.includes(typ)) {
    busyDays.add(d.toISOString().slice(0,10));
  }
}

// === Schritt 3: freien Tag finden ===
const minDate = new Date(now.getTime() + MIN_LEAD_DAYS * 86400000);
const weekdayDE = ['So','Mo','Di','Mi','Do','Fr','Sa'];

function findFreeDayOnWeekday(targetWeekday) {
  for (let day = 1; day <= 31; day++) {
    const probe = new Date(Date.UTC(year, month, day));
    if (probe.getUTCMonth() !== month) break;
    if (probe.getUTCDay() !== targetWeekday) continue;
    if (probe < minDate) continue;
    const iso = probe.toISOString().slice(0,10);
    if (!busyDays.has(iso)) return probe;
  }
  return null;
}
function findFirstFreeWeekday() {
  for (let day = 1; day <= 31; day++) {
    const probe = new Date(Date.UTC(year, month, day));
    if (probe.getUTCMonth() !== month) break;
    const wd = probe.getUTCDay();
    if (wd === 0 || wd === 6) continue;
    if (probe < minDate) continue;
    const iso = probe.toISOString().slice(0,10);
    if (!busyDays.has(iso)) return probe;
  }
  return null;
}

let chosen = findFreeDayOnWeekday(PREFERENCE_WEEKDAY);
let fallback_used = null;
if (!chosen) { chosen = findFreeDayOnWeekday(ALTERNATE_WEEKDAY); if (chosen) fallback_used = 'ALTERNATE_WEEKDAY'; }
if (!chosen) { chosen = findFirstFreeWeekday(); if (chosen) fallback_used = 'ANY_WEEKDAY'; }

if (!chosen) {
  return [{ json: {
    decision: 'NO_FREE_DAY',
    year, month: month + 1,
    candidate_id, candidate_thema, candidate_typ,
    reason: 'Kein freier Werktag im Monat gefunden (alle belegt).'
  }}];
}

const chosen_iso_date = chosen.toISOString().slice(0,10);
const chosen_iso_full = `${chosen_iso_date}T00:00:00Z`;
const [yy,mm,dd] = chosen_iso_date.split('-');
const chosen_de = `${dd}.${mm}.${yy}`;
const chosen_weekday = weekdayDE[chosen.getUTCDay()];

const ts = new Date().toISOString().slice(0,16).replace('T',' ');
const log_append = `\n${ts} WF-04: [AUTO_RELEASE] auto-geplant auf ${chosen_de} (${chosen_weekday}). Freier Tag, keine Reels/Stories. fallback=${fallback_used ?? 'none'}.`;
const new_log = (candidate_log + log_append).trim();

return [{ json: {
  decision: 'OK',
  year, month: month + 1,
  candidate_id, candidate_thema, candidate_typ,
  chosen_iso_date, chosen_iso_full, chosen_de, chosen_weekday,
  posting_time: POSTING_TIME,
  fallback_used, new_log
}}];
